module top_module(sin, sout);input wire [3:0] sin;
output wire [6:0] sout;
reg [6:0] unused_SEG_buf;

  always @ (sin)
  begin
    case(sin)
      4'h0: unused_SEG_buf <= 7'b0111111;
      4'h1: unused_SEG_buf <= 7'b0000110;
      4'h2: unused_SEG_buf <= 7'b1011011;
      4'h3: unused_SEG_buf <= 7'b1001111;
      4'h4: unused_SEG_buf <= 7'b1100110;
      4'h5: unused_SEG_buf <= 7'b1101101;
      4'h6: unused_SEG_buf <= 7'b1111101;
      4'h7: unused_SEG_buf <= 7'b0000111;
      4'h8: unused_SEG_buf <= 7'b1111111;
      4'h9: unused_SEG_buf <= 7'b1101111;
      default: unused_SEG_buf <= 7'b0000000;
    endcase
  end 

  assign sout = unused_SEG_buf;

endmodule
